/// The `date` decode flows through `thetadatadx::decode::row_date`, which
/// accepts `Number`, `Timestamp`, and `Text` cells uniformly — so this tick
/// decodes either the documented Text-ISO shape or any future
/// Number/Timestamp narrowing without a per-parser branch.
#[must_use]
#[derive(Debug, Clone, Copy)]
#[repr(C, align(64))]
pub struct InterestRateTick {
    /// Report creation date as a YYYYMMDD integer.
    pub date: i32,
    /// Interest rate expressed as a percent (1.25 means 1.25%).
    pub rate: f64,
}

/// Implied volatility tick -- 14 fields.
///
/// The snapshot variant (`option_snapshot_greeks_implied_volatility`) emits
/// a 4-column subset (`ms_of_day, implied_vol, iv_error, date`); the
/// generator's optional-column path defaults the missing fields to 0.0 so
/// the snapshot decode keeps working.
#[must_use]
#[derive(Debug, Clone, Copy)]
#[repr(C, align(64))]
pub struct IvTick {
    /// Milliseconds since midnight Eastern Time.
    pub ms_of_day: i32,
    /// Last NBBO bid price.
    pub bid: f64,
    /// Implied volatility solved at the bid price.
    pub bid_implied_volatility: f64,
    /// Midpoint of the bid and ask prices.
    pub midpoint: f64,
    /// Implied volatility solved from the option price.
    pub implied_volatility: f64,
    /// Last NBBO ask price.
    pub ask: f64,
    /// Implied volatility solved at the ask price.
    pub ask_implied_volatility: f64,
    /// Residual pricing error of the implied-volatility solve.
    pub iv_error: f64,
    /// Timestamp of the underlying price, milliseconds since midnight ET.
    pub underlying_ms_of_day: i32,
    /// Underlying price used in the calculation (midpoint of the underlying).
    pub underlying_price: f64,
    /// Trading date as a YYYYMMDD integer.
    pub date: i32,
    /// Contract expiration (`YYYYMMDD`). Populated on wildcard queries, 0 otherwise.
    pub expiration: i32,
    /// Contract strike price in dollars. Populated on wildcard queries, 0.0 otherwise.
    pub strike: f64,
    /// Contract right: `'C'` for a call, `'P'` for a put. `'\0'` on single-contract queries.
    pub right: char,
}

impl IvTick {
    /// Unix epoch milliseconds (UTC, DST-aware) combining `date`
    /// with `ms_of_day` (Eastern-Time milliseconds-of-day). Returns
    /// `None` when `date` is absent (`0`) or `ms_of_day` is outside
    /// the milliseconds-of-day domain. The raw integer fields stay
    /// primary; this accessor is a convenience at the epoch boundary.
    #[must_use]
    pub fn timestamp_ms(&self) -> Option<i64> {
        crate::tdbe::time::date_ms_to_epoch_ms(self.date, self.ms_of_day)
    }
    /// Unix epoch milliseconds (UTC, DST-aware) combining `date`
    /// with `underlying_ms_of_day` (Eastern-Time milliseconds-of-day). Returns
    /// `None` when `date` is absent (`0`) or `underlying_ms_of_day` is outside
    /// the milliseconds-of-day domain. The raw integer fields stay
    /// primary; this accessor is a convenience at the epoch boundary.
    #[must_use]
    pub fn underlying_timestamp_ms(&self) -> Option<i64> {
        crate::tdbe::time::date_ms_to_epoch_ms(self.date, self.underlying_ms_of_day)
    }
}

