/// Quote tick -- 13 fields + midpoint. NBBO quote data.
///
/// Wire layout: the full shape is 11 columns (`ms_of_day`,
/// `bid_size`, `bid_exchange`, `bid`, `bid_condition`, `ask_size`,
/// `ask_exchange`, `ask`, `ask_condition`, `price_type`, `date`).
/// The four exchange / condition columns are NOT in the `required` list
/// below, so when the wire omits them the generated parser skips their
/// column pass and the `0` seed stands; this lets the decoder accept
/// subset NBBO layouts (e.g. the
/// 6-field `[ms_of_day, bid_size, bid, ask_size, ask, date]` shape some
/// storage tiers emit) without erroring, while still decoding the full
/// 11-field shape bit-exact when every column is present.
#[must_use]
#[derive(Debug, Clone, Copy)]
#[repr(C, align(64))]
pub struct QuoteTick {
    /// Milliseconds since midnight Eastern Time.
    pub ms_of_day: i32,
    /// Last NBBO bid size.
    pub bid_size: i32,
    /// Exchange code of the NBBO bid.
    pub bid_exchange: i32,
    /// Last NBBO bid price.
    pub bid: f64,
    /// Quote condition code on the bid side.
    pub bid_condition: i32,
    /// Last NBBO ask size.
    pub ask_size: i32,
    /// Exchange code of the NBBO ask.
    pub ask_exchange: i32,
    /// Last NBBO ask price.
    pub ask: f64,
    /// Quote condition code on the ask side.
    pub ask_condition: i32,
    /// Trading date as a YYYYMMDD integer.
    pub date: i32,
    /// Contract expiration (`YYYYMMDD`). Populated on wildcard queries, 0 otherwise.
    pub expiration: i32,
    /// Contract strike price in dollars. Populated on wildcard queries, 0.0 otherwise.
    pub strike: f64,
    /// Contract right: `'C'` for a call, `'P'` for a put. `'\0'` on single-contract queries.
    pub right: char,
    /// Pre-computed midpoint: `(bid + ask) / 2.0`.
    pub midpoint: f64,
}

impl QuoteTick {
    /// Unix epoch milliseconds (UTC, DST-aware) combining `date`
    /// with `ms_of_day` (Eastern-Time milliseconds-of-day). Returns
    /// `None` when `date` is absent (`0`) or `ms_of_day` is outside
    /// the milliseconds-of-day domain. The raw integer fields stay
    /// primary; this accessor is a convenience at the epoch boundary.
    #[must_use]
    pub fn timestamp_ms(&self) -> Option<i64> {
        crate::tdbe::time::date_ms_to_epoch_ms(self.date, self.ms_of_day)
    }
}

/// Per-trade union Greeks tick -- every Greek the v3 server publishes on
/// `option_history_trade_greeks_all`, paired with the trade-side execution
